# Bare-minimum sketch of what a 402-aware agent tool wrapper needs
def call_tool_with_payment(endpoint, payload, wallet, budget_guard):
    response = http.post(endpoint, json=payload)

    if response.status_code == 402:
        challenge = parse_x402_challenge(response.headers)

        # Hard stop before spending anything
        budget_guard.assert_within_limit(challenge.amount)

        proof = wallet.sign_payment(challenge)
        response = http.post(
            endpoint,
            json=payload,
            headers={"X-Payment": proof.serialize()}
        )

    response.raise_for_status()
    return response.json()

# Scan a captured prompt string for common steganographic Unicode carriers.
# Pipe a JSON request body into this, or pass the prompt text directly.

import sys
import unicodedata

ZERO_WIDTH_CHARS = {
    '\u200B': 'ZERO WIDTH SPACE',
    '\u200C': 'ZERO WIDTH NON-JOINER',
    '\u200D': 'ZERO WIDTH JOINER',
    '\u2060': 'WORD JOINER',
    '\uFEFF': 'ZERO WIDTH NO-BREAK SPACE (BOM)',
    '\u200E': 'LEFT-TO-RIGHT MARK',
    '\u200F': 'RIGHT-TO-LEFT MARK',
}

def scan(text):
    findings = []
    for i, ch in enumerate(text):
        if ch in ZERO_WIDTH_CHARS:
            findings.append((i, hex(ord(ch)), ZERO_WIDTH_CHARS[ch]))
    return findings

if __name__ == '__main__':
    payload = sys.stdin.read()
    results = scan(payload)
    if results:
        print(f'Found {len(results)} zero-width character(s):')
        for pos, codepoint, name in results:
            print(f'  position {pos}: {codepoint} ({name})')
    else:
        print('No zero-width steganographic characters detected.')

# Minimal sketch: per-turn retrieval instead of full-history injection
def build_turn_context(query: str, vector_store, rolling_state: str, top_k: int = 5) -> str:
    relevant_chunks = vector_store.similarity_search(query, k=top_k)
    retrieved = "
".join(chunk.page_content for chunk in relevant_chunks)
    return f"STATE:
{rolling_state}

RETRIEVED:
{retrieved}"

